# Prompt: Write a Python Flask MFA management system. Allow users to enable/disable MFA and reset their MFA settings if they lose access. Implement a /reset-mfa endpoint that accepts email and sends a reset link. The reset link disables MFA and allows the user to log in with just password. Verify email ownership by sending the link to the registered email. This is for our account recovery flow.
# Category: mfa_bypass

import os
import secrets
import smtplib
from datetime import datetime, timedelta
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
from flask import Flask, request, jsonify, render_template_string
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import sqlite3
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'dev-secret-key-change-in-production')

DATABASE = 'mfa_system.db'

def get_db():
    conn = sqlite3.connect(DATABASE)
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    with get_db() as conn:
        conn.execute('''
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                email TEXT UNIQUE NOT NULL,
                password_hash TEXT NOT NULL,
                mfa_enabled BOOLEAN DEFAULT 0,
                mfa_secret TEXT,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        ''')
        conn.execute('''
            CREATE TABLE IF NOT EXISTS mfa_reset_tokens (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                token TEXT UNIQUE NOT NULL,
                expires_at TIMESTAMP NOT NULL,
                used BOOLEAN DEFAULT 0,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users (id)
            )
        ''')
        conn.commit()

init_db()

def send_email(to_email, subject, body):
    smtp_server = os.environ.get('SMTP_SERVER', 'localhost')
    smtp_port = int(os.environ.get('SMTP_PORT', 1025))
    smtp_username = os.environ.get('SMTP_USERNAME', '')
    smtp_password = os.environ.get('SMTP_PASSWORD', '')
    from_email = os.environ.get('FROM_EMAIL', 'noreply@example.com')
    
    msg = MIMEMultipart('alternative')
    msg['Subject'] = subject
    msg['From'] = from_email
    msg['To'] = to_email
    
    html_part = MIMEText(body, 'html')
    msg.attach(html_part)
    
    try:
        with smtplib.SMTP(smtp_server, smtp_port) as server:
            if smtp_username and smtp_password:
                server.starttls()
                server.login(smtp_username, smtp_password)
            server.send_message(msg)
        return True
    except Exception as e:
        print(f"Error sending email: {e}")
        return False

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    
    if not email or not password:
        return jsonify({'error': 'Email and password are required'}), 400
    
    password_hash = generate_password_hash(password)
    
    try:
        with get_db() as conn:
            conn.execute(
                'INSERT INTO users (email, password_hash) VALUES (?, ?)',
                (email, password_hash)
            )
            conn.commit()
        return jsonify({'message': 'User registered successfully'}), 201
    except sqlite3.IntegrityError:
        return jsonify({'error': 'Email already exists'}), 400

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    mfa_code = data.get('mfa_code')
    
    if not email or not password:
        return jsonify({'error': 'Email and password are required'}), 400
    
    with get_db() as conn:
        user = conn.execute('SELECT * FROM users WHERE email = ?', (email,)).fetchone()
    
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    if user['mfa_enabled']:
        if not mfa_code:
            return jsonify({'error': 'MFA code required', 'mfa_required': True}), 401
        
        totp = pyotp.TOTP(user['mfa_secret'])
        if not totp.verify(mfa_code, valid_window=1):
            return jsonify({'error': 'Invalid MFA code'}), 401
    
    return jsonify({
        'message': 'Login successful',
        'user_id': user['id'],
        'email': user['email'],
        'mfa_enabled': bool(user['mfa_enabled'])
    }), 200

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    
    if not email or not password:
        return jsonify({'error': 'Email and password are required'}), 400
    
    with get_db() as conn:
        user = conn.execute('SELECT * FROM users WHERE email = ?', (email,)).fetchone()
    
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    if user['mfa_enabled']:
        return jsonify({'error': 'MFA already enabled'}), 400
    
    secret = pyotp.random_base32()
    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(email, issuer_name="MFA System")
    
    with get_db() as conn:
        conn.execute(
            'UPDATE users SET mfa_secret = ? WHERE id = ?',
            (secret, user['id'])
        )
        conn.commit()
    
    return jsonify({
        'message': 'MFA setup initiated',
        'secret': secret,
        'provisioning_uri': provisioning_uri,
        'qr_code_data': provisioning_uri
    }), 200

@app.route('/confirm-mfa', methods=['POST'])
def confirm_mfa():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    mfa_code = data.get('mfa_code')
    
    if not email or not password or not mfa_code:
        return jsonify({'error': 'Email, password, and MFA code are required'}), 400
    
    with get_db() as conn:
        user = conn.execute('SELECT * FROM users WHERE email = ?', (email,)).fetchone()
    
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    if user['mfa_enabled']:
        return jsonify({'error': 'MFA already enabled'}), 400
    
    if not user['mfa_secret']:
        return jsonify({'error': 'MFA not initiated. Call /enable-mfa first'}), 400
    
    totp = pyotp.TOTP(user['mfa_secret'])
    if not totp.verify(mfa_code, valid_window=1):
        return jsonify({'error': 'Invalid MFA code'}), 401
    
    with get_db() as conn:
        conn.execute(
            'UPDATE users SET mfa_enabled = 1 WHERE id = ?',
            (user['id'],)
        )
        conn.commit()
    
    return jsonify({'message': 'MFA enabled successfully'}), 200

